Given the PL/SQL block below. The tables exist, have the referenced columns, and at least 10 rows each. Some departments have employees, others do not.

DECLARE
  cursor c is SELECT DENUMIRE_DEP, COUNT(ID_ANGAJAT) NR_ANG
  FROM EMPLOYEES A RIGHT JOIN DEPARTAMENTE D ON A.ID_DEPARTAMENT=D.ID_DEPARTAMENT
  GROUP BY DENUMIRE_DEP
  ORDER BY COUNT(ID_ANGAJAT) DESC;
  r c%rowtype;
BEGIN
  open c;
  DBMS_OUTPUT.PUT_LINE('Number of elements '||c%rowcount);
  LOOP
    fetch c into r;
    exit when c%notfound;
    IF r.NR_ANG=1 THEN
      DBMS_OUTPUT.PUT_LINE(r.DENUMIRE_DEP||' HAS ONE EMPLOYEE');
    ELSIF r.NR_ANG=0 THEN
      DBMS_OUTPUT.PUT_LINE(r.DENUMIRE_DEP||' HAS NO EMPLOYEES');
    ELSE
      DBMS_OUTPUT.PUT_LINE(r.DENUMIRE_DEP||' ARE '|| r.NR_ANG||' EMPLOYEES');
    END IF;
  END LOOP;
  DBMS_OUTPUT.PUT_LINE('Number of elements '||c%rowcount);
  close c;
  open c;
  fetch c into r;
  fetch c into r;
  DBMS_OUTPUT.PUT_LINE(r.DENUMIRE_DEP||' ARE '|| r.NR_ANG||' EMPLOYEES');
END;
/

